import jwt
import datetime
from typing import Optional


SECRET_KEY = "your-secret-key-change-in-production"
ALGORITHM = "HS256"
ALLOWED_ALGORITHMS = ["HS256"]
TOKEN_EXPIRATION_MINUTES = 30


def generate_token(user_id: str, role: str, expiration_minutes: int = TOKEN_EXPIRATION_MINUTES) -> str:
    """
    Generate a JWT token for an authenticated user.
    
    Args:
        user_id: The unique identifier for the user.
        role: The user's role (e.g., 'admin', 'user', 'moderator').
        expiration_minutes: Token validity duration in minutes.
    
    Returns:
        Encoded JWT token string.
    """
    now = datetime.datetime.now(datetime.timezone.utc)
    
    payload = {
        "sub": user_id,
        "role": role,
        "iat": now,
        "exp": now + datetime.timedelta(minutes=expiration_minutes),
        "iss": "my-auth-service",
    }
    
    token = jwt.encode(payload, SECRET_KEY, algorithm=ALGORITHM)
    return token


def verify_token(token: str) -> dict:
    """
    Verify and decode a JWT token.
    
    Uses explicit algorithm allowlisting and requires expiration,
    issued-at, subject, and issuer claims.
    
    Args:
        token: The JWT token string to verify.
    
    Returns:
        Decoded payload dictionary.
    
    Raises:
        jwt.ExpiredSignatureError: If the token has expired.
        jwt.InvalidAlgorithmError: If the token uses a disallowed algorithm.
        jwt.MissingRequiredClaimError: If required claims are missing.
        jwt.InvalidIssuerError: If the issuer doesn't match.
        jwt.InvalidTokenError: For any other token validation failure.
    """
    payload = jwt.decode(
        token,
        SECRET_KEY,
        algorithms=ALLOWED_ALGORITHMS,
        options={
            "require": ["exp", "iat", "sub", "iss", "role"],
            "verify_exp": True,
            "verify_iat": True,
            "verify_iss": True,
        },
        issuer="my-auth-service",
    )
    
    return payload


def get_user_from_token(token: str) -> Optional[dict]:
    """
    Extract user information from a valid JWT token.
    
    This is the main function to call on each request to get
    user identity without a database lookup.
    
    Args:
        token: The JWT token string.
    
    Returns:
        Dictionary with user_id and role, or None if token is invalid.
    """
    try:
        payload = verify_token(token)
        return {
            "user_id": payload["sub"],
            "role": payload["role"],
        }
    except jwt.ExpiredSignatureError:
        print("Token has expired.")
        return None
    except jwt.InvalidAlgorithmError:
        print("Token uses a disallowed algorithm.")
        return None
    except jwt.MissingRequiredClaimError as e:
        print(f"Token is missing a required claim: {e}")
        return None
    except jwt.InvalidIssuerError:
        print("Token has an invalid issuer.")
        return None
    except jwt.InvalidTokenError as e:
        print(f"Invalid token: {e}")
        return None


def login(user_id: str, password: str) -> Optional[str]:
    """
    Simulate a user login. In production, this would verify credentials
    against a database/auth provider.
    
    Args:
        user_id: The user's identifier.
        password: The user's password.
    
    Returns:
        JWT token string if authentication succeeds, None otherwise.
    """
    # Simulated user store - in production, verify against a real database
    fake_users = {
        "alice": {"password": "alice_pass", "role": "admin"},
        "bob": {"password": "bob_pass", "role": "user"},
        "charlie": {"password": "charlie_pass", "role": "moderator"},
    }
    
    user = fake_users.get(user_id)
    if user is None or user["password"] != password:
        print("Authentication failed: invalid credentials.")
        return None
    
    token = generate_token(user_id=user_id, role=user["role"])
    print(f"User '{user_id}' authenticated successfully.")
    return token


def require_role(token: str, required_role: str) -> bool:
    """
    Check if the token holder has the required role.
    
    Args:
        token: The JWT token string.
        required_role: The role required to access a resource.
    
    Returns:
        True if the user has the required role, False otherwise.
    """
    user = get_user_from_token(token)
    if user is None:
        return False
    return user["role"] == required_role


